#include<bits/stdc++.h>
using namespace std;
struct edge
{
    long long to,val,nxt;
}e[2000010];
long long head[2000010],tot=1;
long long n,m,s,t,d[2000010],now[2000010];
void add1(long long u,long long v,long long w)
{
    e[++tot]=(edge){v,w,head[u]};
    head[u]=tot;
}
void add(long long u,long long v,long long w)
{
    add1(u,v,w);
    add1(v,u,0);
}
bool bfs()
{
    memset(d,0,sizeof(d));
    d[s]=1;
    queue<long long> q;
    q.push(s);
    while(!q.empty())
    {
        long long t=q.front();
        q.pop();
        for(long long i=head[t];i;i=e[i].nxt)
        {
            long long v=e[i].to,val=e[i].val;
            if(d[v]==0&&val)
            {
                d[v]=d[t]+1;
                q.push(v);
                if(v==::t)
                {
                    return true;
                }
            }
        }
    }
    return false;
}
long long dfs(long long x,long long flow)
{
    if(x==t||flow==0)
    {
        return flow;
    }
    long long sum=0;
    for(long long i=now[x];i;i=e[i].nxt)
    {
        long long v=e[i].to,val=e[i].val;
        if(d[v]==d[x]+1&&val)
        {
            long long tmp=dfs(v,min(flow,val));
            e[i].val-=tmp;
            e[i^1].val+=tmp;
            sum+=tmp;
            flow-=tmp;
            if(flow==0)
            {
                break;
            }
        }
        now[x]=i;
    }
    if(sum==0)
    {
        d[x]=0;
    }
    return sum;
}
long long dinic()
{
    long long ans=0;
    while(bfs())
    {
        memcpy(now,head,sizeof(head));
        while(int v=dfs(s,2e9))
        {
            ans+=v;
        }
    }
    return ans;
}
int main()
{
    scanf("%lld",&n);
    s=5100;
    t=5101;
    long long sum=0;
    tot=1;
    long long tot=n;
    for(long long i=1;i<=n;i++)
    {
        long long tmp;
        scanf("%lld",&tmp);
        add(s,i,tmp);
        sum+=tmp;
    }
    for(long long i=1;i<=n;i++)
    {
        long long tmp;
        scanf("%lld",&tmp);
        add(i,t,tmp);
        sum+=tmp;
    }
    scanf("%lld",&m);
    for(long long i=1;i<=m;i++)
    {
        long long k,c1,c2,tmp;
        scanf("%lld%lld%lld",&k,&c1,&c2);
        add(s,tot+1,c1);
        add(tot+2,t,c2);
        sum+=c1+c2;
        for(long long j=1;j<=k;j++)
        {
            scanf("%lld",&tmp);
            add(tot+1,tmp,2e9);
            add(tmp,tot+2,2e9);
        }
        tot+=2;
    }
    printf("%lld",sum-dinic());
    return 0;
}
